package qa.loop;

public class doWhile {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
        int num=11;
        
        //int num= 16; //do while loop also check the condition but last
		
		do { 
			System.out.println("num: "+num);
			num++;
		} while  (num<=15); 
		
	}
}
	


